    quot_are.data[x] = qm31_add_re_re(q_rr, c_rr);
    quot_aim.data[x] = qm31_add_re_im(q_ri, c_ri);
    quot_bre.data[x] = qm31_add_im_re(q_ir, c_ir);
    quot_bim.data[x] = qm31_add_im_im(q_ii, c_ii);

  }
}

